package graphql

import (
	"context"
	"fmt"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/bead"
)

// beadStore returns a bead.Store rooted at the per-request working directory
// (from ctx via WithWorkingDir, falling back to r.WorkingDir).
func (r *mutationResolver) beadStore(ctx context.Context) *bead.Store {
	return projectBeadStore(r.workingDir(ctx))
}

// beadModelFromBead converts a bead.Bead to the GraphQL Bead model.
func beadModelFromBead(b *bead.Bead) *Bead {
	gql := &Bead{
		ID:        b.ID,
		Title:     b.Title,
		Status:    b.Status,
		Priority:  b.Priority,
		IssueType: b.IssueType,
		CreatedAt: b.CreatedAt.UTC().Format(time.RFC3339),
		UpdatedAt: b.UpdatedAt.UTC().Format(time.RFC3339),
		Labels:    b.Labels,
	}
	if b.Owner != "" {
		gql.Owner = &b.Owner
	}
	if b.CreatedBy != "" {
		gql.CreatedBy = &b.CreatedBy
	}
	if b.Parent != "" {
		gql.Parent = &b.Parent
	}
	if b.Description != "" {
		gql.Description = &b.Description
	}
	if b.Acceptance != "" {
		gql.Acceptance = &b.Acceptance
	}
	if b.Notes != "" {
		gql.Notes = &b.Notes
	}
	for _, d := range b.Dependencies {
		dep := &Dependency{
			IssueID:     d.IssueID,
			DependsOnID: d.DependsOnID,
			Type:        d.Type,
		}
		if d.CreatedAt != "" {
			dep.CreatedAt = &d.CreatedAt
		}
		if d.CreatedBy != "" {
			dep.CreatedBy = &d.CreatedBy
		}
		if d.Metadata != "" {
			dep.Metadata = &d.Metadata
		}
		gql.Dependencies = append(gql.Dependencies, dep)
	}
	return gql
}

// BeadCreate is the resolver for the beadCreate mutation.
func (r *mutationResolver) BeadCreate(ctx context.Context, input BeadInput) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if input.Title == "" {
		return nil, fmt.Errorf("title is required")
	}

	b := &bead.Bead{
		Title: input.Title,
	}
	if input.Status != nil {
		b.Status = *input.Status
	}
	if input.Priority != nil {
		b.Priority = *input.Priority
	}
	if input.IssueType != nil {
		b.IssueType = *input.IssueType
	}
	if input.Labels != nil {
		b.Labels = input.Labels
	}
	if input.Parent != nil {
		b.Parent = *input.Parent
	}
	if input.Description != nil {
		b.Description = *input.Description
	}
	if input.Acceptance != nil {
		b.Acceptance = *input.Acceptance
	}
	if input.Notes != nil {
		b.Notes = *input.Notes
	}

	store := r.beadStore(ctx)
	if err := store.Create(ctx, b); err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadUpdate is the resolver for the beadUpdate mutation.
func (r *mutationResolver) BeadUpdate(ctx context.Context, id string, input BeadUpdateInput) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	mutate := func(b *bead.Bead) error {
		if input.Title != nil {
			b.Title = *input.Title
		}
		if input.Priority != nil {
			b.Priority = *input.Priority
		}
		if input.IssueType != nil {
			b.IssueType = *input.IssueType
		}
		if input.Labels != nil {
			b.Labels = input.Labels
		}
		if input.Parent != nil {
			b.Parent = *input.Parent
		}
		if input.Description != nil {
			b.Description = *input.Description
		}
		if input.Acceptance != nil {
			b.Acceptance = *input.Acceptance
		}
		if input.Notes != nil {
			b.Notes = *input.Notes
		}
		return nil
	}
	var err error
	if input.Status != nil {
		err = store.UpdateWithLifecycleStatus(id, *input.Status, bead.LifecycleTransitionOptions{
			Reason: "graphql bead update",
			Source: "graphql:beadUpdate",
		}, mutate)
	} else {
		err = store.Update(ctx, id, func(b *bead.Bead) {
			_ = mutate(b)
		})
	}
	if err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadClaim is the resolver for the beadClaim mutation.
func (r *mutationResolver) BeadClaim(ctx context.Context, id string, assignee string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	if err := store.Claim(id, assignee); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadUnclaim is the resolver for the beadUnclaim mutation.
func (r *mutationResolver) BeadUnclaim(ctx context.Context, id string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	if err := store.Unclaim(id); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadReopen is the resolver for the beadReopen mutation.
func (r *mutationResolver) BeadReopen(ctx context.Context, id string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}

	store := r.beadStore(ctx)
	if err := store.Reopen(id, "graphql bead reopen", ""); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadApprove is the resolver for the beadApprove mutation.
// Transitions a proposed bead to open status (operator approval).
func (r *mutationResolver) BeadApprove(ctx context.Context, id string, note string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if strings.TrimSpace(note) == "" {
		return nil, fmt.Errorf("note is required")
	}

	store := r.beadStore(ctx)
	if err := store.TransitionLifecycle(id, bead.StatusOpen, bead.LifecycleTransitionOptions{
		ManualReopen: true,
		Reason:       "graphql bead approve",
		Actor:        "operator",
		Source:       "graphql:beadApprove",
	}, nil); err != nil {
		return nil, err
	}

package federation

import (
	"bytes"
	"context"
	"crypto/tls"
	"encoding/json"
	"errors"
	"fmt"
	"io"
	"log"
	"net/http"
	"net/url"
	"strings"
	"sync"
	"time"
)

// DefaultFanOutMaxConcurrency caps the number of in-flight per-spoke requests.
const DefaultFanOutMaxConcurrency = 8

// DefaultFanOutPerNodeTimeout is the default per-node deadline for one fan-out call.
const DefaultFanOutPerNodeTimeout = 5 * time.Second

// SkipReason is a short, machine-readable code describing why a spoke was
// skipped before any HTTP call was issued.
type SkipReason string

const (
	// SkipReasonIncompatibleVersion indicates the version handshake against the
	// hub's own version+schema rejected this spoke (e.g. major mismatch,
	// schema mismatch, unparseable ddx_version, …). The Handshake reason is
	// included in the logged message.
	SkipReasonIncompatibleVersion SkipReason = "incompatible_version"
	// SkipReasonMissingCapability indicates the spoke does not advertise one of
	// the capabilities required for this query.
	SkipReasonMissingCapability SkipReason = "missing_capability"
	// SkipReasonInvalidURL indicates the spoke's persisted URL did not parse.
	SkipReasonInvalidURL SkipReason = "invalid_url"
)

// NodeOutcomeKind describes how a single spoke contributed (or did not
// contribute) to a fan-out call. The hub uses this to update per-spoke status
// distinctly: offline (immediate transport failure on this fan-out) vs stale
// (heartbeat-overdue badge from the registry) vs ok.
type NodeOutcomeKind string

const (
	// OutcomeOK means the spoke returned a response (any HTTP 2xx).
	OutcomeOK NodeOutcomeKind = "ok"
	// OutcomeOffline means the transport itself failed: connection refused,
	// DNS error, TLS handshake failed, mid-response disconnect, etc. The hub
	// flips the spoke's registry status to StatusOffline on this outcome.
	OutcomeOffline NodeOutcomeKind = "offline"
	// OutcomeTimeout means the per-node timeout fired before a response was
	// fully received. Distinct from offline so callers can keep the spoke's
	// last-known status (likely stale) rather than promote it to offline.
	OutcomeTimeout NodeOutcomeKind = "timeout"
	// OutcomeHTTPError means the spoke responded with a non-2xx status. The
	// transport worked, so we do not flip to offline; the body is captured.
	OutcomeHTTPError NodeOutcomeKind = "http_error"
	// OutcomeSkipped means the spoke was filtered out before fan-out; see
	// NodeResult.SkipReason.
	OutcomeSkipped NodeOutcomeKind = "skipped"
)

// FanOutRequest is the GraphQL payload to send to every active spoke.
type FanOutRequest struct {
	Query         string         `json:"query"`
	OperationName string         `json:"operationName,omitempty"`
	Variables     map[string]any `json:"variables,omitempty"`
	// RequiredCapabilities, if non-empty, filters out spokes that do not
	// advertise every named capability in their SpokeRecord.Capabilities.
	RequiredCapabilities []string `json:"-"`
}

// NodeResult is a single spoke's contribution to a fan-out call.
type NodeResult struct {
	NodeID string
	URL    string
	// Status, when non-empty, is the registry status the hub should record for
	// this spoke as a result of this fan-out (StatusOffline on transport
	// failure). Empty means "do not change registry status".
	Status SpokeStatus
	// Outcome classifies how this spoke contributed.
	Outcome NodeOutcomeKind
	// Response is the raw GraphQL response body for OutcomeOK. The hub merges
	// it into the federated response shape. Empty otherwise.
	Response json.RawMessage
	// HTTPStatus is the HTTP status code seen, or 0 on transport failure.
	HTTPStatus int
	// Err is the underlying error for non-OK outcomes.
	Err error
	// SkipReason is set when Outcome == OutcomeSkipped.
	SkipReason SkipReason
	// SkipDetail is a free-form human message accompanying SkipReason.
	SkipDetail string
	// Duration is the wall time spent on this spoke's call.
	Duration time.Duration
}

// FanOutResult is the merged outcome of a fan-out call.
type FanOutResult struct {
	// Responses holds one entry per spoke that returned 2xx, keyed by node_id.
	// The value is the raw GraphQL response body.
	Responses map[string]json.RawMessage
	// Errors holds one entry per spoke that produced any non-OK outcome
	// (offline, timeout, http_error). Skipped spokes are NOT in this map —
	// they appear in Skipped instead. Keyed by node_id.
	Errors map[string]error
	// Skipped holds one entry per spoke filtered out before fan-out, keyed by
	// node_id, with the SkipReason as the value.
	Skipped map[string]SkipReason
	// StatusUpdates lists the (node_id → new status) changes the hub should
	// apply to its registry as a side effect of this fan-out. Currently only
	// transport-level failures (StatusOffline) are emitted here; heartbeat-
	// driven status (stale) is left to the registry's own time-based reconcile.
	StatusUpdates map[string]SpokeStatus
	// Nodes is the per-node detail (every spoke considered, including skipped).
	// Order matches the input registry order for deterministic test output.
	Nodes []NodeResult
}

// FanOutClient executes fan-out GraphQL queries across a federation registry.
type FanOutClient struct {
	// HTTPClient is used for spoke /graphql calls. Nil → a default client that
	// accepts self-signed TLS certs (matches the spoke server's auto-cert).
	HTTPClient *http.Client
	// MaxConcurrency caps concurrent in-flight requests. ≤0 → default.
	MaxConcurrency int
	// PerNodeTimeout is the per-spoke deadline. ≤0 → default.
	PerNodeTimeout time.Duration
	// HubDDxVersion / HubSchemaVersion drive the version handshake gate.
	// Empty → version filter is skipped (test convenience).
	HubDDxVersion    string
	HubSchemaVersion string
	// Logger receives info/warn lines; nil → log.Printf.
	Logger func(format string, args ...any)
	// Now is the time source used for Duration measurement. Nil → time.Now.
	Now func() time.Time
}

// NewFanOutClient builds a FanOutClient with defaults filled in.
func NewFanOutClient() *FanOutClient {
	return &FanOutClient{
		HTTPClient: &http.Client{
			// Per-request deadlines drive cancellation; this is just a safety
			// net for misbehaving servers that never close the connection.
			Timeout: 30 * time.Second,
			Transport: &http.Transport{
				TLSClientConfig: &tls.Config{InsecureSkipVerify: true}, //nolint:gosec
			},
		},
		MaxConcurrency: DefaultFanOutMaxConcurrency,
		PerNodeTimeout: DefaultFanOutPerNodeTimeout,
	}
}

func (c *FanOutClient) logf(format string, args ...any) {
	if c.Logger != nil {
		c.Logger(format, args...)
		return
	}
	log.Printf(format, args...)
}

func (c *FanOutClient) now() time.Time {
	if c.Now != nil {
		return c.Now()
	}
	return time.Now()
}

func (c *FanOutClient) maxConcurrency() int {
	if c.MaxConcurrency <= 0 {
		return DefaultFanOutMaxConcurrency
	}
	return c.MaxConcurrency
}

func (c *FanOutClient) perNodeTimeout() time.Duration {
	if c.PerNodeTimeout <= 0 {
		return DefaultFanOutPerNodeTimeout
	}
	return c.PerNodeTimeout
}

func (c *FanOutClient) httpClient() *http.Client {
	if c.HTTPClient != nil {
		return c.HTTPClient
	}
	return http.DefaultClient
}

// Execute fans out req across spokes. Returns a merged FanOutResult; never
// returns a non-nil error for per-spoke failures — those are surfaced through
// FanOutResult.Errors. A non-nil error is reserved for misuse (e.g. nil req).
//
// The set of spokes considered is the input slice. Callers typically pass the
// hub registry's spokes filtered by Status == active|stale (offline/degraded
// handling depends on policy and is left to the caller). Skipped spokes still
// appear in the per-node Nodes detail with OutcomeSkipped + SkipReason.
//
// Cancellation: if ctx is canceled, in-flight goroutines abort their HTTP
// calls and return OutcomeOffline (with ctx.Err() as cause); callers that want
// to distinguish caller-cancellation from spoke failure should check ctx.Err()
// after Execute returns.
func (c *FanOutClient) Execute(ctx context.Context, spokes []SpokeRecord, req *FanOutRequest) (*FanOutResult, error) {
	if req == nil {
		return nil, errors.New("federation: fanout request is nil")
	}
	if strings.TrimSpace(req.Query) == "" {
		return nil, errors.New("federation: fanout request query is empty")
	}

	body, err := json.Marshal(struct {
		Query         string         `json:"query"`
		OperationName string         `json:"operationName,omitempty"`
		Variables     map[string]any `json:"variables,omitempty"`
	}{req.Query, req.OperationName, req.Variables})
	if err != nil {
		return nil, fmt.Errorf("federation: marshal fanout query: %w", err)
	}

	results := make([]NodeResult, len(spokes))
	sem := make(chan struct{}, c.maxConcurrency())
	var wg sync.WaitGroup

	for i := range spokes {
		i := i
		s := spokes[i]
		// Pre-flight filters: version, capability, URL.
		if skip, reason, detail := c.preflightSkip(s, req.RequiredCapabilities); skip {
			c.logf("federation fanout: skip node_id=%q reason=%s detail=%q", s.NodeID, reason, detail)
			results[i] = NodeResult{
				NodeID:     s.NodeID,
				URL:        s.URL,
				Outcome:    OutcomeSkipped,
				SkipReason: reason,
				SkipDetail: detail,
			}
			continue
		}

		wg.Add(1)
		go func() {
			defer wg.Done()
			select {
			case sem <- struct{}{}:
			case <-ctx.Done():
				results[i] = NodeResult{
					NodeID:  s.NodeID,
					URL:     s.URL,
					Outcome: OutcomeOffline,
					Status:  StatusOffline,
					Err:     ctx.Err(),
				}
				return
			}
			defer func() { <-sem }()

// Package bead implements the on-disk bead tracker.
//
// Size envelope (ddx-f8a11202):
//
// Individual bead fields — description, acceptance, notes, and each event's
// body — are bounded by MaxFieldBytes (65,535 bytes). This matches upstream
// bd's Dolt TEXT column limit so DDx-authored beads can always round-trip
// through `bd import`. Writers exceeding the cap are truncated with a
// `…[truncated, N bytes]` marker at AppendEvent; callers that need to
// preserve the full payload (notably reviewer streams) should persist to a
// sidecar artifact under `.ddx/executions/<id>/` and record a path
// reference in the event body.
//
// On the read side, scanners use a 16MB buffer — real-world incidents have
// produced 1.46MB bead rows and ~7MB session-log rows when writers bypassed
// the cap. 16MB comfortably fits a bead with dozens of maxed-out fields and
// matches the scanner in the agent package.
package bead

import (
	"bufio"
	"bytes"
	"context"
	"crypto/rand"
	"encoding/hex"
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"strconv"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/config"
	gitpkg "github.com/DocumentDrivenDX/ddx/internal/git"
)

// Store manages beads via a pluggable backend.
type Store struct {
	Collection string
	Dir        string
	File       string
	Prefix     string
	LockDir    string
	LockWait   time.Duration
	backend    RawBackend // nil means use built-in JSONL
}

// Compile-time check: *Store satisfies the high-level Backend interface
// declared in backend.go. This is the contract chaos_test.go and (eventually)
// cli/cmd callers program against.
var _ Backend = (*Store)(nil)

// Compile-time checks: *Store satisfies the TD-027 dependency sub-interfaces.
var _ BeadDependencyReader = (*Store)(nil)
var _ BeadDependencyWriter = (*Store)(nil)

// Compile-time checks: *Store satisfies the TD-027 archive and interchange sub-interfaces.
var _ BeadArchive = (*Store)(nil)
var _ BeadInterchangeReader = (*Store)(nil)
var _ BeadInterchangeWriter = (*Store)(nil)

type StoreOption func(*Store)

// WithCollection selects the logical bead collection. The default collection
// remains "beads", which maps to "beads.jsonl" in the JSONL backend.
func WithCollection(name string) StoreOption {
	return func(s *Store) {
		if cleaned := normalizeCollection(name); cleaned != "" {
			s.Collection = cleaned
		}
	}
}

// NewStore creates a store with the given directory.
// Defaults can be overridden via options or environment.
func NewStore(dir string, opts ...StoreOption) *Store {
	if dir == "" {
		dir = envOr("DDX_BEAD_DIR", ".ddx")
	}
	workingDir := dir
	if filepath.Base(dir) == ".ddx" {
		workingDir = filepath.Dir(dir)
	}
	prefix := envOr("DDX_BEAD_PREFIX", "")
	var configBackend string
	if cfg, err := config.LoadWithWorkingDir(workingDir); err == nil && cfg != nil && cfg.Bead != nil {
		if prefix == "" && cfg.Bead.IDPrefix != "" {
			prefix = cfg.Bead.IDPrefix
		}
		configBackend = cfg.Bead.Backend
	}
	if prefix == "" {
		prefix = detectPrefix(workingDir)
	}
	// Backend selection: env var wins, then config, then jsonl default.
	backendType := os.Getenv("DDX_BEAD_BACKEND")
	if backendType == "" {
		backendType = configBackend
	}
	if backendType == "" {
		backendType = BackendJSONL
	}

	s := &Store{
		Collection: DefaultCollection,
		Dir:        dir,
		Prefix:     prefix,
		LockWait:   parseDurationOr("DDX_BEAD_LOCK_TIMEOUT", 10*time.Second),
	}
	for _, opt := range opts {
		if opt != nil {
			opt(s)
		}
	}
	spec := DefaultRegistry().Resolve(CollectionID(s.Collection))
	s.File, s.LockDir = spec.PathsUnder(dir)

	// Set up external backend if configured. bd/br lack per-collection
	// scoping in their CLI, so non-default collections (e.g. beads-archive)
	// route through a JSONL fallback the external backend transparently
	// delegates to. The default collection always goes straight to bd/br
	// to preserve the existing interchange contract (schema_compat_test.go,
	// import/export round-trip).
	switch backendType {
	case BackendBD, BackendBR:
		var fallback RawBackend
		if s.Collection != DefaultCollection {
			fallback = NewJSONLBackend(s.Dir, s.File, s.LockDir, s.LockWait)
		}
		if ext, err := NewExternalBackendWithFallback(backendType, s.Collection, fallback); err == nil {
			s.backend = ext
		}
		// Fall through to JSONL if tool not available
	case BackendAxon:
		s.backend = NewAxonBackend(s.Dir, s.LockWait)
	}

	return s
}

// NewStoreWithCollection creates a store for a named logical collection.
func NewStoreWithCollection(dir, collection string) *Store {
	return NewStore(dir, WithCollection(collection))
}

// Init creates the storage directory and file.
func (s *Store) Init(ctx context.Context) error {
	if err := ctx.Err(); err != nil {
		return err
	}
	if s.backend != nil {
		return s.backend.Init()
	}
	if err := os.MkdirAll(s.Dir, 0o755); err != nil {
		return fmt.Errorf("bead: init dir: %w", err)
	}
	f, err := os.OpenFile(s.File, os.O_CREATE|os.O_WRONLY, 0o644)
	if err != nil {
		return fmt.Errorf("bead: init file: %w", err)
	}
	return f.Close()
}

// GenID generates a unique bead ID with the configured prefix.
func (s *Store) GenID(ctx context.Context) (string, error) {
	if err := ctx.Err(); err != nil {
		return "", err
	}
	prefix := s.Prefix
	if prefix == "" {
		prefix = DefaultIDPrefix
	} else if !strings.HasSuffix(prefix, "-") {
		prefix += "-"
	}
	return RandomHexIDGenerator{Prefix: prefix, Bytes: 4}.GenID(ctx)
}

// ReadAll loads all beads from the configured backend.
func (s *Store) ReadAll(ctx context.Context) ([]Bead, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		return all, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))
	}
	return beads, nil
}

// ReadAllFiltered loads all beads, folds them by latest-wins, and returns only
// those for which the predicate returns true. When the predicate is nil every
// bead is returned (equivalent to ReadAll). The predicate is applied at the
// per-entry parse boundary after fold — matched beads are appended directly to
// the return slice without first being held in an intermediate full-corpus
// list, so queries that match a small subset avoid materializing the
// mismatches (ddx-9ce6842a Part 2 step 2: filter pushdown).
func (s *Store) ReadAllFiltered(ctx context.Context, pred func(Bead) bool) ([]Bead, error) {
	if err := ctx.Err(); err != nil {
		return nil, err
	}
	if s.backend != nil {
		all, err := s.backend.ReadAll()
		if err != nil {
			return nil, err
		}
		if pred == nil {
			return all, nil
		}
		out := make([]Bead, 0, len(all))
		for _, b := range all {
			if pred(b) {
				out = append(out, b)
			}
		}
		return out, nil
	}
	beads, warnings, err := s.readAllRaw()
	if err != nil {
		return nil, fmt.Errorf("bead: read %s: %w", s.File, err)
	}
	beads = foldLatestBeads(beads)
	for _, warning := range warnings {
		fmt.Fprintln(os.Stderr, warning)
	}
	if len(warnings) > 0 && len(beads) > 0 {
		repaired, repairErr := s.repairJSONL()
		if repairErr != nil {
			return beads, fmt.Errorf("bead: repair %s: %w", s.File, repairErr)
		}
		if repaired {
			fmt.Fprintf(os.Stderr, "bead: repaired %s; backup written to %s.bak\n", s.File, s.File)
		}
	}
	if len(beads) == 0 && len(warnings) > 0 {
		return nil, fmt.Errorf("bead: read %s: %d malformed record(s), 0 valid", s.File, len(warnings))

	}

	if err := store.AppendEvent(id, bead.BeadEvent{
		Kind:    "human-resolution",
		Summary: "approve",
		Body:    note,
		Actor:   "operator",
		Source:  "graphql",
	}); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadCancel is the resolver for the beadCancel mutation.
// Cancels a bead from open, in_progress, blocked, or proposed status.
func (r *mutationResolver) BeadCancel(ctx context.Context, id string, reason string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if strings.TrimSpace(reason) == "" {
		return nil, fmt.Errorf("reason is required")
	}

	store := r.beadStore(ctx)
	if err := store.TransitionLifecycle(id, bead.StatusCancelled, bead.LifecycleTransitionOptions{
		Reason: reason,
		Actor:  "operator",
		Source: "graphql:beadCancel",
	}, nil); err != nil {
		return nil, err
	}

	if err := store.AppendEvent(id, bead.BeadEvent{
		Kind:    "human-resolution",
		Summary: "cancel",
		Body:    reason,
		Actor:   "operator",
		Source:  "graphql",
	}); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

// BeadBlock is the resolver for the beadBlock mutation.
// Blocks a bead with an external blocker reason.
func (r *mutationResolver) BeadBlock(ctx context.Context, id string, externalBlockerReason string) (*Bead, error) {
	if r.workingDir(ctx) == "" {
		return nil, fmt.Errorf("working directory not configured")
	}
	if strings.TrimSpace(externalBlockerReason) == "" {
		return nil, fmt.Errorf("externalBlockerReason is required")
	}

	store := r.beadStore(ctx)
	if err := store.TransitionLifecycle(id, bead.StatusBlocked, bead.LifecycleTransitionOptions{
		ExternalBlockerReason: externalBlockerReason,
		Reason:                "graphql bead block",
		Actor:                 "operator",
		Source:                "graphql:beadBlock",
	}, nil); err != nil {
		return nil, err
	}

	b, err := store.Get(ctx, id)
	if err != nil {
		return nil, err
	}
	return beadModelFromBead(b), nil
}

package federation

import (
	"fmt"
	"net/http"
	"strings"
)

// ForwardMutationRequest describes a hub-to-spoke owner-targeted mutation
// envelope. The request is deliberately narrow: it carries the origin and
// forwarding trail plus the single owning node/project pair that is allowed to
// execute the write.
type ForwardMutationRequest struct {
	OriginIdentity  string
	ForwardingPath  []string
	RequestID       string
	IdempotencyKey  string
	TargetNodeID    string
	TargetProjectID string
	ExpectedVersion *string

	// RequiredCapabilities lets the hub declare the minimum spoke capability
	// set needed for this mutation. The writer can reject requests that do not
	// advertise the required surface.
	RequiredCapabilities []string

	// Body and Headers carry the actual mutation envelope to the owning spoke.
	Body    []byte
	Headers map[string]string
}

// ForwardMutationResponse is the owning node's reply to a forwarded mutation
// request. It mirrors the request metadata so callers can correlate a result
// with the original write envelope.
type ForwardMutationResponse struct {
	OriginIdentity  string
	ForwardingPath  []string
	RequestID       string
	IdempotencyKey  string
	TargetNodeID    string
	TargetProjectID string
	ExpectedVersion *string

	RequiredCapabilities []string
	StatusCode           int
	Headers              http.Header
	Body                 []byte
}

// Validate checks the request for the narrow owner-targeted shape. The typed
// refusals are intentionally specific so callers can surface a stable reason.
func (r *ForwardMutationRequest) Validate() error {
	if r == nil {
		return ErrForwardMutationBroadcastLike
	}
	if strings.TrimSpace(r.TargetNodeID) == "" {
		return ErrForwardMutationMissingOwner
	}
	if strings.TrimSpace(r.TargetProjectID) == "" {
		return ErrForwardMutationMissingProject
	}
	if len(r.ForwardingPath) == 0 {
		return ErrForwardMutationBroadcastLike
	}
	return nil
}

// ForwardMutationRefusalKind is the stable refusal class surfaced by the
// federation forwarding contract.
type ForwardMutationRefusalKind string

const (
	ForwardMutationRefusalOffline        ForwardMutationRefusalKind = "offline"
	ForwardMutationRefusalStale          ForwardMutationRefusalKind = "stale"
	ForwardMutationRefusalReadOnly       ForwardMutationRefusalKind = "read_only"
	ForwardMutationRefusalMissingProject ForwardMutationRefusalKind = "missing-project"
	ForwardMutationRefusalMissingOwner   ForwardMutationRefusalKind = "missing-owner"
	ForwardMutationRefusalBroadcastLike  ForwardMutationRefusalKind = "broadcast-like"
)

func (k ForwardMutationRefusalKind) String() string { return string(k) }

// ForwardMutationRefusalError is a typed refusal that lets callers check a
// stable reason with errors.Is while still preserving a human-readable detail.
type ForwardMutationRefusalError struct {
	Kind   ForwardMutationRefusalKind
	Detail string
}

func (e *ForwardMutationRefusalError) Error() string {
	if e == nil {
		return "federation: forward mutation refused"
	}
	if e.Detail == "" {
		return fmt.Sprintf("federation: forward mutation refused: %s", e.Kind)
	}
	return fmt.Sprintf("federation: forward mutation refused: %s: %s", e.Kind, e.Detail)
}

// Is makes errors.Is match on refusal kind rather than pointer identity.
func (e *ForwardMutationRefusalError) Is(target error) bool {
	t, ok := target.(*ForwardMutationRefusalError)
	if !ok || e == nil || t == nil {
		return false
	}
	return e.Kind == t.Kind
}

var (
	ErrForwardMutationOffline        = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalOffline}
	ErrForwardMutationStale          = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalStale}
	ErrForwardMutationReadOnly       = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalReadOnly}
	ErrForwardMutationMissingProject = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalMissingProject}
	ErrForwardMutationMissingOwner   = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalMissingOwner}
	ErrForwardMutationBroadcastLike  = &ForwardMutationRefusalError{Kind: ForwardMutationRefusalBroadcastLike}
)

package graphql

// Federation resolvers (B14.6b). The hub fans out a small set of read-only
// queries to every active spoke via the B14.6a fan-out client, decorates
// each row with routing metadata (node_id, project_id, project_url,
// write_capability, status), and merges the per-spoke responses into a
// single result. The same provider surface also exposes owner-targeted write
// forwarding so mutation callers can route a single write to its owning
// project without changing the read fan-out behavior.

import (
	"context"
	"encoding/json"
	"strings"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/federation"
)

// FederationProvider exposes the hub-side state required by the federated
// query resolvers. The Resolver is wired with a nil provider on non-hub
// servers; resolvers degrade to empty-list responses in that case.
type FederationProvider interface {
	// Spokes returns a snapshot of registered spokes. Implementations should
	// return a copy that callers may sort or filter without affecting the
	// underlying registry.
	Spokes() []federation.SpokeRecord
	// FanOut executes the supplied request against every spoke returned by
	// Spokes (the implementation may apply its own active/stale policy) and
	// returns the merged FanOutResult.
	FanOut(ctx context.Context, req *federation.FanOutRequest) (*federation.FanOutResult, error)
	// ForwardMutation routes one owner-targeted mutation to the owning spoke.
	// The request carries the origin, forwarding trail, and target identity
	// metadata needed to preserve the write contract.
	ForwardMutation(ctx context.Context, req *federation.ForwardMutationRequest) (*federation.ForwardMutationResponse, error)
}

// federationCapWrite is the capability string a spoke advertises when it
// allows writes from federated callers. Read-only fan-out is the v1 default
// so this field is always false until a spoke explicitly opts in.
const federationCapWrite = "write"

// federationIdentityPrefix mirrors the synthetic capability used by the hub
// to stash the identity fingerprint on a SpokeRecord. Filtered out of the
// FederationNode.capabilities surface so clients never see it.
const federationIdentityPrefix = "@identity:"

// FederationNodes returns one row per registered spoke decorated with the
// most recent fan-out outcome. When the server is not in hub mode (Resolver
// has no FederationProvider) the result is an empty list.
func (r *queryResolver) FederationNodes(ctx context.Context) ([]*FederationNode, error) {
	if r.Federation == nil {
		return []*FederationNode{}, nil
	}
	spokes := r.Federation.Spokes()
	out := make([]*FederationNode, 0, len(spokes))
	for _, s := range spokes {
		out = append(out, federationNodeFromSpoke(s, ""))
	}
	return out, nil
}

// FederatedBeads fans out a beads query and merges the resulting edges into
// FederatedBead rows.
func (r *queryResolver) FederatedBeads(ctx context.Context, status *string, label *string, projectID *string) ([]*FederatedBead, error) {
	if r.Federation == nil {
		return []*FederatedBead{}, nil
	}
	const beadsQuery = `query FedBeads($status:String,$label:String,$projectID:String){
  beads(first:200,status:$status,label:$label,projectID:$projectID){
    edges{node{id title status priority issueType owner createdAt createdBy updatedAt labels projectID parent description acceptance notes}}
  }
}`
	vars := map[string]any{}
	if status != nil {
		vars["status"] = *status
	}
	if label != nil {
		vars["label"] = *label
	}
	if projectID != nil {
		vars["projectID"] = *projectID
	}
	res, err := r.Federation.FanOut(ctx, &federation.FanOutRequest{Query: beadsQuery, Variables: vars})
	if err != nil {
		return nil, err
	}
	spokeIndex := indexSpokes(r.Federation.Spokes())
	out := []*FederatedBead{}
	for _, n := range res.Nodes {
		if n.Outcome != federation.OutcomeOK {
			continue
		}
		var resp struct {
			Data struct {
				Beads struct {
					Edges []struct {
						Node *Bead `json:"node"`
					} `json:"edges"`
				} `json:"beads"`
			} `json:"data"`
		}
		if err := json.Unmarshal(n.Response, &resp); err != nil {
			continue
		}
		s := spokeIndex[n.NodeID]
		writeCap := hasCapability(s.Capabilities, federationCapWrite)
		statusStr := string(s.Status)
		for _, e := range resp.Data.Beads.Edges {
			if e.Node == nil {
				continue
			}
			out = append(out, &FederatedBead{
				NodeID:          n.NodeID,
				ProjectID:       e.Node.ProjectID,
				ProjectURL:      n.URL,
				WriteCapability: writeCap,
				Status:          statusStr,
				Bead:            e.Node,
			})
		}
	}
	return out, nil
}

// FederatedRuns fans out a runs query and merges the resulting edges into
// FederatedRun rows.
func (r *queryResolver) FederatedRuns(ctx context.Context, layer *RunLayer, projectID *string) ([]*FederatedRun, error) {
