	for _, n := range res.Nodes {
		if n.Outcome != federation.OutcomeOK {
			continue
		}
		var resp struct {
			Data struct {
				Runs struct {
					Edges []struct {
						Node *Run `json:"node"`
					} `json:"edges"`
				} `json:"runs"`
			} `json:"data"`
		}
		if err := json.Unmarshal(n.Response, &resp); err != nil {
