const (
	federationOriginIdentityHeader      = "X-DDx-Origin-Identity"
	federationCoordinatorIdentityHeader = "X-DDx-Coordinator-Identity"
)

// federationRequestIdentity returns the peer identity attested at the
// transport edge. ts-net callers use the injected X-Tailscale-Node header;
// loopback callers fall back to a localhost:<remote-addr> actor string.
func federationRequestIdentity(r *http.Request) string {
	if node := strings.TrimSpace(r.Header.Get("X-Tailscale-Node")); node != "" {
		return node
	}
	if user := strings.TrimSpace(r.Header.Get("X-Tailscale-User")); user != "" {
		return user
	}
	if isLocalhost(r) && r.RemoteAddr != "" {
		return "localhost:" + r.RemoteAddr
	}
	return ""
}

// federationSelfIdentity returns the server's attested identity for
// coordinator-forwarded mutations.
func (s *Server) federationSelfIdentity() string {
	if name := strings.TrimSpace(s.state.Node.Name); name != "" {
		return name
	}
	return strings.TrimSpace(s.state.Node.ID)
}

// federationIdentityKnown reports whether identity is a registered federation
// peer or the server's own attested identity.
func (s *Server) federationIdentityKnown(identity string) bool {
	identity = strings.TrimSpace(identity)
	if identity == "" {
		return false
	}
	if identity == s.state.Node.ID || identity == s.state.Node.Name {
		return true
	}
	if s.hub == nil {
		return false
	}
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	if s.hub.registry.FindSpoke(identity) != nil {
		return true
	}
	for _, spoke := range s.hub.registry.Spokes {
		if spoke.Name == identity {
			return true
		}
	}
	return false
}

// requireTrustedForwarded gates /graphql. Direct localhost / ts-net callers
// keep the existing trusted-transport behavior. Forwarded mutations must
// carry both attestation headers, and the spoke verifies the coordinator
// identity against the direct peer identity observed on the socket.
func (s *Server) requireTrustedForwarded(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		origin := strings.TrimSpace(r.Header.Get(federationOriginIdentityHeader))
		coordinator := strings.TrimSpace(r.Header.Get(federationCoordinatorIdentityHeader))
		if origin == "" && coordinator == "" {
			if !isTrusted(r) {
				writeJSON(w, http.StatusForbidden, map[string]string{"error": "graphql is localhost-only"})
				return
			}
			next(w, r)
			return
		}
		if origin == "" || coordinator == "" {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: forwarded mutation requires origin and coordinator attestation"})
			return
		}
		if !isTrusted(r) {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: trusted connection required for forwarded mutation"})
			return
		}
		directPeer := federationRequestIdentity(r)
		if directPeer == "" {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: unable to verify coordinator identity"})
			return
		}
		if coordinator != directPeer {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: coordinator identity does not match peer attestation"})
			return
		}
		if !s.federationIdentityKnown(coordinator) {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: untrusted coordinator identity"})
			return
		}
		if strings.HasPrefix(origin, "localhost:") {
			next(w, r)
			return
		}
		if !s.federationIdentityKnown(origin) {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: untrusted origin identity"})
			return
		}
		next(w, r)
	}
}

// isLocalhostAddr parses a RemoteAddr and checks for loopback.
func isLocalhostAddr(addr string) bool {
	host := addr
	if idx := strings.LastIndex(host, ":"); idx >= 0 {
		host = host[:idx]
	}
	host = strings.Trim(host, "[]")
	ip := net.ParseIP(host)
	if ip != nil {
		return ip.IsLoopback()
	}
	return host == "localhost"
}

// requireTrusted wraps a handler so non-loopback, non-tailnet requests are
// rejected with 403 before the handler executes.
func requireTrusted(next http.HandlerFunc) http.HandlerFunc {
	return func(w http.ResponseWriter, r *http.Request) {
		if !isTrusted(r) {
			writeJSON(w, http.StatusForbidden, map[string]string{"error": "forbidden: trusted connection required"})
			return
		}
		next(w, r)
	}
}

// projectContextKey is the context key under which the resolved ProjectEntry
// for a /api/projects/{project}/... request is stored.
type projectContextKey struct{}

// projectFromContext returns the ProjectEntry previously injected by
// projectScoped or singletonScoped middleware, if any.
func projectFromContext(ctx context.Context) (ProjectEntry, bool) {
	p, ok := ctx.Value(projectContextKey{}).(ProjectEntry)
	return p, ok
}

package graphql

import (
	"context"
	"time"

	"github.com/vektah/gqlparser/v2/gqlerror"
)

// ArtifactRegenerate is the resolver for the artifactRegenerate mutation.
//
// It looks up the artifact by ID and dispatches a server-side regeneration
// using the artifact's recorded generator metadata (generatedBy.runId and
// promptSummary). When the artifact has no generator metadata it returns a
// typed GraphQL error (extension code NO_GENERATOR_METADATA) so the UI can
// keep its Regenerate button disabled with an explanatory tooltip.
func (r *mutationResolver) ArtifactRegenerate(ctx context.Context, artifactID string) (*ArtifactRegenerateResult, error) {
	if r.workingDir(ctx) == "" {
		return nil, &gqlerror.Error{
			Message:    "working directory not configured",
			Extensions: map[string]any{"code": "NOT_CONFIGURED"},
		}
	}

	// Resolve the artifact across all known projects so the mutation works
	// even when the caller passed only the artifact ID. We re-use the same
	// collection logic used by the Artifact and Artifacts resolvers.
	artifact, err := findArtifactByID(r.Resolver, artifactID)
	if err != nil {
		return nil, err
	}
	if artifact == nil {
		return nil, &gqlerror.Error{
			Message:    "artifact not found",
			Extensions: map[string]any{"code": "ARTIFACT_NOT_FOUND"},
		}
	}
	if artifact.GeneratedBy == nil {
		return nil, &gqlerror.Error{
			Message: "artifact has no generator metadata; nothing to regenerate",
			Extensions: map[string]any{
				"code": "NO_GENERATOR_METADATA",
			},
		}
	}

	runID := newDispatchID("regen", artifactID)
	record := artifactRegenerateRecord{
		ID:            runID,
		ArtifactID:    artifactID,
		ArtifactPath:  artifact.Path,
		SourceRunID:   artifact.GeneratedBy.RunID,
		PromptSummary: artifact.GeneratedBy.PromptSummary,
		Status:        queuedPlaceholderState,
		CreatedAt:     time.Now().UTC(),
	}
	if err := writeJSONRecord(r.workingDir(ctx), "artifact-regenerations", runID, record); err != nil {
		return nil, err
	}

	return &ArtifactRegenerateResult{
		RunID:  runID,
		Status: queuedPlaceholderState,
	}, nil
}

type artifactRegenerateRecord struct {
	ID            string    `json:"id"`
	ArtifactID    string    `json:"artifact_id"`
	ArtifactPath  string    `json:"artifact_path"`
	SourceRunID   string    `json:"source_run_id"`
	PromptSummary string    `json:"prompt_summary"`
	Status        string    `json:"status"`
	CreatedAt     time.Time `json:"created_at"`
}

// findArtifactByID locates an artifact across the resolver's projects by ID.
// Falls back to scanning the resolver working directory when no project state
// is configured. Returns (nil, nil) when no artifact matches.
func findArtifactByID(r *Resolver, id string) (*Artifact, error) {
	roots := []string{}
	if r.State != nil {
		for _, p := range r.State.GetProjectSnapshots(false) {
			if p.Path != "" {
				roots = append(roots, p.Path)
			}
		}
	}
	// findArtifactByID has no ctx; fall back to the resolver's startup
	// WorkingDir for the unscoped no-State case. The State-based path above
	// remains the primary lookup, so this only matters when no projects
	// are registered.
	if len(roots) == 0 && r.WorkingDir != "" {
		roots = append(roots, r.WorkingDir)
	}
	for _, root := range roots {
		artifacts, err := collectArtifacts(root)
		if err != nil {
			continue
		}
		for _, a := range artifacts {
			if a.ID == id {
				return a, nil
			}
		}
	}
	return nil, nil
}

