// federationDoRequest is a small helper that runs a request against an
// httptest.NewServer wrapping s.Handler() so we exercise the real net/http
// stack (RemoteAddr is populated by the test server, matching production
// trust-gating behavior). Pass remote="loopback" for trusted, "external"
// for an explicitly non-loopback request.
func federationDoRequest(t *testing.T, s *Server, method, path string, body any, remote string) *http.Response {
	t.Helper()
	var buf bytes.Buffer
	if body != nil {
		if err := json.NewEncoder(&buf).Encode(body); err != nil {
			t.Fatalf("encode: %v", err)
		}
	}
	req := httptest.NewRequest(method, path, &buf)
	req.Header.Set("Content-Type", "application/json")
	switch remote {
	case "external":
		req.RemoteAddr = "203.0.113.1:54321"
	default:
		req.RemoteAddr = "127.0.0.1:54321"
	}
	rec := httptest.NewRecorder()
	s.Handler().ServeHTTP(rec, req)
	return rec.Result()
}

func newHubServer(t *testing.T, allowPlainHTTP bool) *Server {
	t.Helper()
	dir := setupTestDir(t)
	s := New(":0", dir)
	s.EnableHubMode(allowPlainHTTP)
	// Pin hub version for handshake tests.
	s.hub.hubDDxVersion = "0.10.5"
	s.hub.hubSchemaVer = "1"
	return s
}

func setServerIdentity(t *testing.T, s *Server, identity string) {
	t.Helper()
	s.state.Node.Name = identity
	s.state.Node.ID = identity
}

func registerFederationPeer(t *testing.T, s *Server, nodeID string) {
	t.Helper()
	s.hub.mu.Lock()
	defer s.hub.mu.Unlock()
	if err := s.hub.registry.UpsertSpoke(federation.SpokeRecord{
		NodeID: nodeID,
		Name:   nodeID,
		URL:    "https://" + nodeID + ":7743",
		Status: federation.StatusActive,
	}); err != nil {
		t.Fatalf("register peer %q: %v", nodeID, err)
	}
}

func decodeBody(t *testing.T, resp *http.Response, dst any) {
	t.Helper()
	if err := json.NewDecoder(resp.Body).Decode(dst); err != nil {
		t.Fatalf("decode: %v", err)
	}
}

// AC: Routes mounted only when --hub-mode.
func TestFederationRoutesNotMountedWithoutHubMode(t *testing.T) {
	dir := setupTestDir(t)
	s := New(":0", dir)
	// Hub mode NOT enabled — federation routes must not be on the mux at all.
	for _, p := range s.routePatterns {
		if strings.Contains(p, "/api/federation/") {
			t.Fatalf("federation route registered without EnableHubMode: %s", p)
		}
	}
	// And a register request must not produce a federation register response
	// (no node_id-bearing JSON body); the request falls through to the SPA
	// fallback or a non-2xx error, but never the federation handler.
	resp := federationDoRequest(t, s, "POST", "/api/federation/register",
		map[string]string{"node_id": "n1"}, "loopback")
	var maybe federationRegisterResponse
	_ = json.NewDecoder(resp.Body).Decode(&maybe)
	if maybe.NodeID == "n1" {
		t.Fatalf("federation register handler ran with hub-mode off")
	}
}

// AC: routes mounted when hub-mode enabled.
func TestFederationRoutesMountedInHubMode(t *testing.T) {
	s := newHubServer(t, false)
	want := []string{
		"POST /api/federation/register",
		"POST /api/federation/heartbeat",
		"GET /api/federation/spokes",
		"DELETE /api/federation/spokes/{id}",
		"POST /api/federation/projects/{project}/graphql",
	}
	have := map[string]bool{}
	for _, p := range s.routePatterns {
		have[p] = true
	}
	for _, p := range want {
		if !have[p] {
			t.Errorf("expected route %q not mounted", p)
		}
	}
}

func TestFederationForwardMutation_RoutesToProjectOwner(t *testing.T) {
	s := newHubServer(t, false)
	setServerIdentity(t, s, "coord-456")

	var calls int
	var gotMethod string
	var gotPath string
	var gotHeaders http.Header
	var gotBody []byte
	spoke := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		calls++
		gotMethod = r.Method
		gotPath = r.URL.Path
		gotHeaders = r.Header.Clone()
		gotBody, _ = io.ReadAll(r.Body)
		w.WriteHeader(http.StatusOK)
		_, _ = w.Write([]byte(`{"data":{"forwarded":true}}`))
	}))
	t.Cleanup(spoke.Close)

	s.hub.mu.Lock()
	s.hub.registry = federation.NewRegistry()
	if err := s.hub.registry.UpsertSpoke(federation.SpokeRecord{
		NodeID:       "node-a",
		Name:         "alpha",
		URL:          spoke.URL,
		ProjectIDs:   []string{"proj-a"},
		Capabilities: []string{"read", "write"},
		Status:       federation.StatusActive,
	}); err != nil {
		s.hub.mu.Unlock()
		t.Fatalf("upsert spoke: %v", err)
	}
	s.hub.mu.Unlock()

	req := httptest.NewRequest(http.MethodPost, "/api/federation/projects/proj-a/graphql", bytes.NewBufferString(`{"query":"mutation { doThing }"}`))
	req.Header.Set("Content-Type", "application/json")
	req.Header.Set("X-Tailscale-Node", "origin-123")
	req.Header.Set("X-DDx-Origin-Identity", "tampered-origin")
	req.Header.Set("X-DDx-Coordinator-Identity", "tampered-coord")
	req.RemoteAddr = "127.0.0.1:54321"

	rec := httptest.NewRecorder()
	s.Handler().ServeHTTP(rec, req)
	resp := rec.Result()
	defer func() { _ = resp.Body.Close() }()

	if resp.StatusCode != http.StatusOK {
		t.Fatalf("status = %d, body=%s", resp.StatusCode, rec.Body.String())
	}
	if calls != 1 {
		t.Fatalf("spoke calls = %d, want 1", calls)
	}
	if gotMethod != http.MethodPost {
		t.Fatalf("spoke method = %s, want POST", gotMethod)
	}
	if gotPath != "/graphql" {
		t.Fatalf("spoke path = %s, want /graphql", gotPath)
	}
	if got := gotHeaders.Get("X-DDx-Origin-Identity"); got != "origin-123" {
		t.Fatalf("origin header = %q, want %q", got, "origin-123")
	}
	if got := gotHeaders.Get("X-DDx-Coordinator-Identity"); got != "coord-456" {
		t.Fatalf("coordinator header = %q, want %q", got, "coord-456")
	}
	if string(gotBody) != `{"query":"mutation { doThing }"}` {
		t.Fatalf("spoke body = %s", string(gotBody))
	}
	if body := rec.Body.String(); body != `{"data":{"forwarded":true}}` {
		t.Fatalf("response body = %s", body)
	}
}

func TestFederationForwardMutationHTTP_IdempotentRequestID(t *testing.T) {
	s := newHubServer(t, false)
	setServerIdentity(t, s, "coord-456")

	var calls int
	spoke := httptest.NewServer(http.HandlerFunc(func(w http.ResponseWriter, r *http.Request) {
		calls++
		w.Header().Set("X-Spoke-Call", "first")
		w.WriteHeader(http.StatusCreated)
		_, _ = w.Write([]byte(`{"data":{"created":true}}`))
	}))
	t.Cleanup(spoke.Close)

	s.hub.mu.Lock()
	s.hub.registry = federation.NewRegistry()
	if err := s.hub.registry.UpsertSpoke(federation.SpokeRecord{
		NodeID:       "node-a",
